async (params, browser) => {
  // Search Glassdoor jobs
  await browser.open('https://www.glassdoor.com/Job/jobs.htm')

  // Wait for job results
  await browser.waitForSelector('.jobCard, .react-job-listing, [data-test="jobListing"], [class*="JobsList_jobListItem"], li[data-jobid]', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll to load more jobs
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract job listings
  const search_results = await browser.evaluate(`const jobs = []; const cards = document.querySelectorAll('.jobCard, .react-job-listing, [data-test="jobListing"], li[data-jobid], [class*="JobsList_jobListItem"]'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const card = cards[i]; const titleEl = card.querySelector('.job-title, .jobTitle, a[data-test="job-title"], [class*="JobCard_jobTitle"], .job-link'); const companyEl = card.querySelector('.employer-name, .job-employer, [data-test="employer-name"], [class*="EmployerProfile_compactEmployerName"], .employer-tile'); const locationEl = card.querySelector('.location, [data-test="emp-location"], [class*="JobCard_location"], .job-location'); const salaryEl = card.querySelector('.salary-estimate, [data-test="detailSalary"], [class*="JobCard_salaryEstimate"], .salary'); const ratingEl = card.querySelector('.rating, [data-test="rating"], .employer-rating'); const linkEl = card.querySelector('a[href*="/job-listing/"], a[href*="/partner/"], a.jobTitle, a.job-link, a[data-test="job-title"]'); let url = ''; if (linkEl) { const href = linkEl.getAttribute('href') || ''; url = href.startsWith('http') ? href : 'https://www.glassdoor.com' + href; } jobs.push({ title: titleEl ? titleEl.textContent.trim() : 'Unknown', company: companyEl ? companyEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', salary_estimate: salaryEl ? salaryEl.textContent.trim() : 'Not listed', company_rating: ratingEl ? ratingEl.textContent.trim() : '', url: url }); } return { query: '' + params.query + '', location: '' + params.location + '', job_count: jobs.length, jobs: jobs }`)

  return search_results
}
